from flask import Flask, jsonify, request
import logging

app = Flask(__name__)

# Set up logging
logging.basicConfig(filename='application.log', level=logging.DEBUG)
logger = logging.getLogger('api')

@app.route('/')
def index():
    return 'Hello, World!'

@app.route('/login', methods=['POST'])
def login():
    # Log request headers and body data for debugging
    logger.debug(f'Received login request with headers: {request.headers}')
    logger.debug(f'Received login request with body data: {request.get_json()}')

    # Authenticate user
    if request.form['username'] == 'admin' and request.form['password'] == 'secret':
        return jsonify({'message': 'Logged in successfully'}), 200
    else:
        return jsonify({'message': 'Invalid username or password'}), 401

@app.route('/protected', methods=['GET'])
def protected():
    # Log user information for debugging
    logger.debug(f'User {request.headers["X-Auth-Token"]} is accessing the protected resource')

    return jsonify({'message': 'Protected resource'}), 200

if __name__ == '__main__':
    app.run(debug=True)